-- 会议生成报告增加copy第三方费用信息
UPDATE `object_validations` SET `label` = '会议报告阶段自动拷贝计划阶段成本中心及第三方费用', `description` = '会议报告阶段自动拷贝计划阶段成本中心及第三方费用', `trigger_code` = 'from orionbase.common import models\nuserid = instance.owner.id\n# 报告阶段自动拷贝计划阶段成本中心\nif (instance.state.name == \'save\') and instance.record_type.name.find(\'_report\'):\n    if instance.id and instance.event_id:\n        to_copy_cost = []\n        from_cost_data = models.CustomObjects4.objects.filter(deleted=0,event_1_id=instance.event_id)\n        if from_cost_data:\n            for data in from_cost_data:\n                data.id = None\n                data.event_1_id = instance.id\n                to_copy_cost.append(data)\n        if to_copy_cost:\n            models.CustomObjects4.objects.bulk_create(to_copy_cost, batch_size=500)\n        to_copy_expense = []\n        from_expense_data = models.CustomObjects5.objects.filter(deleted=0, event_1_id=instance.event_id)\n        if from_expense_data:\n            for data in from_expense_data:\n                data.id = None\n                data.event_1_id = instance.id\n                to_copy_expense.append(data)\n        if to_copy_expense:\n            models.CustomObjects5.objects.bulk_create(to_copy_expense, batch_size=500)' WHERE (`id` = 'f083128a-5353-4ab0-b4ac-462307111ee0');

UPDATE `custom_settings` SET `value` = 'false' WHERE (`key` = 'event_expense_share_user_enable_parent_event');
UPDATE `custom_settings` SET `value` = '[\n    \"ba579c2e-5eee-11e6-80bf-5cc5d4d378cb\",\n    \"bb21a2f0-5eee-11e6-9c65-5cc5d4d378cb\",\n    \"26dfabc7-e40d-4515-ada1-02df95c9d02d\"\n]' WHERE (`key` = 'event_expense_enable_states');
